// Lists how many player heroes have each skill, and which skills nobody picked.
const { list: skillList } = ds.CONFIG.skills;

const nonGMUsers = game.users.filter(u => !u.isGM);
const playerActors = game.actors.filter(a =>
  a.type === 'hero' && nonGMUsers.some(u => a.testUserPermission(u, 'OWNER'))
);

if (!playerActors.length) {
  ui.notifications.warn('No player-owned hero actors found.');
  return;
}

const tally = new Map();
for (const actor of playerActors) {
  for (const skill of (actor.system.skills?.value ?? [])) {
    tally.set(skill, (tally.get(skill) ?? 0) + 1);
  }
}

const picked = [...tally.entries()]
  .sort((a, b) => (skillList[a[0]]?.label ?? a[0]).localeCompare(skillList[b[0]]?.label ?? b[0]))
  .map(([key, count]) => {
    const label = skillList[key]?.label ?? key;
    return count > 1 ? `<strong>${label}</strong> &times;${count}` : label;
  });

const unpicked = Object.entries(skillList)
  .filter(([key]) => !tally.has(key))
  .sort((a, b) => (a[1].label ?? a[0]).localeCompare(b[1].label ?? b[0]))
  .map(([key, { label }]) => label ?? key);

const actorNames = playerActors.map(a => `<em>${a.name}</em>`).join(', ');

const content = `
  <p><strong>Heroes checked (${playerActors.length}):</strong> ${actorNames}</p>
  <hr>
  <p><strong>Skills picked (${tally.size} unique):</strong></p>
  <p style="line-height:1.8">${picked.join(' &nbsp;&middot;&nbsp; ') || '<em>None</em>'}</p>
  <hr>
  <p><strong>Unpicked skills (${unpicked.length}):</strong></p>
  <p style="line-height:1.8;color:#888">${unpicked.join(' &nbsp;&middot;&nbsp; ') || '<em>All skills picked!</em>'}</p>
`;

ChatMessage.create({ content, whisper: game.users.filter(u => u.isGM).map(u => u.id) });
